#' Plot an HRF Object
#'
#' @param x An HRF object
#' @param ... Additional arguments passed to plotting functions
#' @export
plot.HRF <- function(x, ...) {
  t <- seq(0, attr(x, "span"), by = 0.1)
  y <- evaluate(x, t)

  if (is.matrix(y)) {
    matplot(t, y, type = "l", xlab = "Time (s)", ylab = "Response", 
            main = attr(x, "name"), ...)
    legend("topright", paste("Basis", 1:ncol(y)), col = 1:ncol(y), lty = 1:ncol(y))
  } else {
    plot(t, y, type = "l", xlab = "Time (s)", ylab = "Response", 
         main = attr(x, "name"), ...)
    peak_idx <- which.max(y)
    points(t[peak_idx], y[peak_idx], pch = 19, col = "red")
    text(t[peak_idx], y[peak_idx], sprintf("Peak: %.1fs", t[peak_idx]), 
         pos = 3, offset = 0.5)
  }
}

