deriv.HRF <- function(x, t, ...) {
  # Get the number of basis functions
  nb <- nbasis(x)

  # Create result matrix
  result <- matrix(0, nrow = length(t), ncol = nb)

  # For each time point, compute numerical derivative
  for (i in seq_along(t)) {
    t_i <- t[i]

    # Define function to differentiate at time t_i
    f <- function(time) {
      evaluate(x, time)
    }

    # Compute gradient at t_i
    grad_at_t <- numDeriv::grad(f, t_i)

    # Handle both vector and matrix outputs
    if (is.matrix(grad_at_t)) {
      result[i, ] <- grad_at_t[1, ]
    } else {
      result[i, ] <- grad_at_t
    }
  }

  # Return vector if single basis function, matrix otherwise
  if (nb == 1) {
    return(result[, 1])
  } else {
    return(result)
  }
}

